import * as React from "react";

import { Callback, PLUGIN_ZOOM, RenderFunction } from "../../index.js";
import { Zoom } from "./Zoom.js";

declare module "../../types.js" {
  interface LightboxProps {
    /** Zoom plugin settings */
    zoom?: {
      /** Zoom plugin ref */
      ref?: React.ForwardedRef<ZoomRef>;
      /** override minimum zoom level (default: 1.0) */
      minZoom?: number;
      /** ratio of image pixels to physical pixels at maximum zoom level */
      maxZoomPixelRatio?: number;
      /** zoom-in multiplier */
      zoomInMultiplier?: number;
      /** @deprecated - double-tap maximum time delay */
      doubleTapDelay?: number;
      /** @deprecated - double-click maximum time delay */
      doubleClickDelay?: number;
      /** maximum number of zoom-in stops via double-click or double-tap */
      doubleClickMaxStops?: number;
      /** keyboard move distance */
      keyboardMoveDistance?: number;
      /** wheel zoom distance factor */
      wheelZoomDistanceFactor?: number;
      /** @deprecated - pinch zoom distance factor */
      pinchZoomDistanceFactor?: number;
      /** if `true`, enables the experimental pinch zoom implementation slated for v4 */
      pinchZoomV4?: boolean;
      /** if `true`, enables image zoom via scroll gestures for mouse and trackpad users */
      scrollToZoom?: boolean;
    };
  }

  // noinspection JSUnusedGlobalSymbols
  interface AnimationSettings {
    /** zoom animation duration */
    zoom?: number;
  }

  interface Render {
    /** render custom Zoom control in the toolbar */
    buttonZoom?: RenderFunction<ZoomRef>;
    /** render custom Zoom In icon */
    iconZoomIn?: RenderFunction;
    /** render custom Zoom Out icon */
    iconZoomOut?: RenderFunction;
  }

  interface Labels {
    /** `Zoom in` button title */
    "Zoom in"?: string;
    /** `Zoom out` button title */
    "Zoom out"?: string;
  }

  // noinspection JSUnusedGlobalSymbols
  interface RenderSlideProps {
    /** current zoom level */
    zoom?: number;
    /** maximum zoom level */
    maxZoom?: number;
  }

  // noinspection JSUnusedGlobalSymbols
  interface Callbacks {
    /** zoom callback */
    zoom?: Callback<ZoomCallbackProps>;
  }

  /** Zoom callback props */
  interface ZoomCallbackProps {
    /** current zoom level */
    zoom: number;
  }

  // noinspection JSUnusedGlobalSymbols
  interface ToolbarButtonKeys {
    [PLUGIN_ZOOM]: null;
  }

  /** Zoom plugin ref */
  interface ZoomRef {
    /** current zoom level */
    zoom: number;
    /** minimum zoom level */
    minZoom: number;
    /** maximum zoom level */
    maxZoom: number;
    /** horizontal offset */
    offsetX: number;
    /** vertical offset */
    offsetY: number;
    /** if `true`, zoom is unavailable for the current slide */
    disabled: boolean;
    /** increase zoom level using `zoomInMultiplier` */
    zoomIn: Callback;
    /** decrease zoom level using `zoomInMultiplier` */
    zoomOut: Callback;
    /** change zoom level */
    changeZoom: (targetZoom: number, rapid?: boolean, dx?: number, dy?: number) => void;
  }
}

export default Zoom;

--- props ---
import { LightboxProps } from "../../index.js";

export const defaultZoomProps = {
  minZoom: 1,
  maxZoomPixelRatio: 1,
  zoomInMultiplier: 2,
  doubleTapDelay: 300,
  doubleClickDelay: 500,
  doubleClickMaxStops: 2,
  keyboardMoveDistance: 50,
  wheelZoomDistanceFactor: 100,
  pinchZoomDistanceFactor: 100,
  pinchZoomV4: false,
  scrollToZoom: false,
};

function validateMinZoom(minZoom: number) {
  return Math.min(Math.max(minZoom, Number.EPSILON), 1);
}

export function resolveZoomProps(zoom: LightboxProps["zoom"]) {
  const { minZoom, ...rest } = { ...defaultZoomProps, ...zoom };
  return { minZoom: validateMinZoom(minZoom), ...rest };
}

--- Zoom ---
import * as React from "react";

import { addToolbarButton, createModule, isImageSlide, Plugin, PLUGIN_ZOOM } from "../../index.js";
import { resolveZoomProps } from "./props.js";
import { ZoomContextProvider } from "./ZoomController.js";
import { ZoomToolbarControl } from "./ZoomToolbarControl.js";
import { ZoomWrapper } from "./ZoomWrapper.js";

/** Zoom plugin */
export const Zoom: Plugin = ({ augment, addModule }) => {
  augment(({ zoom: zoomProps, toolbar, render, controller, ...restProps }) => {
    const zoom = resolveZoomProps(zoomProps);
    return {
      zoom,
      toolbar: addToolbarButton(toolbar, PLUGIN_ZOOM, <ZoomToolbarControl />),
      render: {
        ...render,
        slide: (props) =>
          isImageSlide(props.slide) ? <ZoomWrapper render={render} {...props} /> : render.slide?.(props),
      },
      controller: { ...controller, preventDefaultWheelY: zoom.scrollToZoom },
      ...restProps,
    };
  });

  addModule(createModule(PLUGIN_ZOOM, ZoomContextProvider));
};

--- wrapper ---
import * as React from "react";

import {
  CLASS_FLEX_CENTER,
  CLASS_FULLSIZE,
  CLASS_SLIDE_WRAPPER,
  CLASS_SLIDE_WRAPPER_INTERACTIVE,
  clsx,
  ContainerRect,
  cssClass,
  ImageSlide,
  isImageSlide,
  LightboxProps,
  RenderSlideProps,
  useLayoutEffect,
  useLightboxProps,
  useLightboxState,
} from "../../index.js";
import { useZoom } from "./ZoomController.js";
import { isResponsiveImageSlide, ResponsiveImage } from "./ResponsiveImage.js";

// using the non-augmented `render` here
export type ZoomWrapperProps = Pick<LightboxProps, "render"> & RenderSlideProps;

/** Zoom wrapper */
export function ZoomWrapper({ render, slide, offset, rect }: ZoomWrapperProps) {
  const [imageDimensions, setImageDimensions] = React.useState<ContainerRect>();
  const zoomWrapperRef = React.useRef<HTMLDivElement>(null);

  const { zoom, maxZoom, offsetX, offsetY, setZoomWrapper } = useZoom();
  const interactive = zoom > 1;

  const { carousel, on } = useLightboxProps();
  const { currentIndex } = useLightboxState();

  useLayoutEffect(() => {
    if (offset === 0) {
      setZoomWrapper({ zoomWrapperRef, imageDimensions });
      return () => setZoomWrapper(undefined);
    }
    return () => {};
  }, [offset, imageDimensions, setZoomWrapper]);

  let rendered = render.slide?.({ slide, offset, rect, zoom, maxZoom });

  if (!rendered && isImageSlide(slide)) {
    const slideProps = {
      slide,
      offset,
      rect,
      render,
      imageFit: carousel.imageFit,
      imageProps: carousel.imageProps,
      onClick: offset === 0 ? () => on.click?.({ index: currentIndex }) : undefined,
    };

    rendered = isResponsiveImageSlide(slide) ? (
      <ResponsiveImage
        {...slideProps}
        slide={slide}
        interactive={interactive}
        rect={offset === 0 ? { width: rect.width * zoom, height: rect.height * zoom } : rect}
      />
    ) : (
      <ImageSlide
        onLoad={(img) => setImageDimensions({ width: img.naturalWidth, height: img.naturalHeight })}
        {...slideProps}
      />
    );
  }

  if (!rendered) return null;

  return (
    <div
      ref={zoomWrapperRef}
      className={clsx(
        cssClass(CLASS_FULLSIZE),
        cssClass(CLASS_FLEX_CENTER),
        cssClass(CLASS_SLIDE_WRAPPER),
        interactive && cssClass(CLASS_SLIDE_WRAPPER_INTERACTIVE),
      )}
      style={
        offset === 0 ? { transform: `scale(${zoom}) translateX(${offsetX}px) translateY(${offsetY}px)` } : undefined
      }
    >
      {rendered}
    </div>
  );
}

--- image rect ---
import {
  ContainerRect,
  isImageFitCover,
  isImageSlide,
  round,
  useLightboxProps,
  useLightboxState,
} from "../../../index.js";
import { useZoomProps } from "./useZoomProps.js";

export function useZoomImageRect(slideRect: ContainerRect, imageDimensions?: ContainerRect) {
  let imageRect: ContainerRect = { width: 0, height: 0 };
  let maxImageRect: ContainerRect = { width: 0, height: 0 };

  const { currentSlide } = useLightboxState();
  const { imageFit } = useLightboxProps().carousel;
  const { maxZoomPixelRatio } = useZoomProps();

  if (slideRect && currentSlide) {
    const slide = { ...currentSlide, ...imageDimensions };
    if (isImageSlide(slide)) {
      const cover = isImageFitCover(slide, imageFit);

      const width = Math.max(...(slide.srcSet?.map((x) => x.width) || []).concat(slide.width ? [slide.width] : []));

      const height = Math.max(...(slide.srcSet?.map((x) => x.height) || []).concat(slide.height ? [slide.height] : []));

      if (width > 0 && height > 0 && slideRect.width > 0 && slideRect.height > 0) {
        maxImageRect = cover
          ? {
              width: Math.round(Math.min(width, (slideRect.width / slideRect.height) * height)),
              height: Math.round(Math.min(height, (slideRect.height / slideRect.width) * width)),
            }
          : { width, height };

        maxImageRect = {
          width: maxImageRect.width * maxZoomPixelRatio,
          height: maxImageRect.height * maxZoomPixelRatio,
        };

        imageRect = cover
          ? {
              width: Math.min(slideRect.width, maxImageRect.width, width),
              height: Math.min(slideRect.height, maxImageRect.height, height),
            }
          : {
              width: Math.round(Math.min(slideRect.width, (slideRect.height / height) * width, width)),
              height: Math.round(Math.min(slideRect.height, (slideRect.width / width) * height, height)),
            };
      }
    }
  }

  const maxZoom = imageRect.width ? Math.max(round(maxImageRect.width / imageRect.width, 5), 1) : 1;

  return { imageRect, maxZoom };
}

--- controller ---
import * as React from "react";

import { ComponentProps, ContainerRect, makeUseContext, useController, ZoomRef } from "../../index.js";
import { useZoomCallback, useZoomImageRect, useZoomProps, useZoomSensors, useZoomState } from "./hooks/index.js";

export type ActiveZoomWrapper = {
  zoomWrapperRef: React.RefObject<HTMLDivElement | null>;
  imageDimensions?: ContainerRect;
};

export type ZoomControllerContextType = ZoomRef & {
  setZoomWrapper: React.Dispatch<React.SetStateAction<ActiveZoomWrapper | undefined>>;
};

export const ZoomControllerContext = React.createContext<ZoomControllerContextType | null>(null);

export const useZoom = makeUseContext("useZoom", "ZoomControllerContext", ZoomControllerContext);

export function ZoomContextProvider({ children }: ComponentProps) {
  const [zoomWrapper, setZoomWrapper] = React.useState<ActiveZoomWrapper>();

  const { slideRect } = useController();
  const { ref, minZoom } = useZoomProps();
  const { imageRect, maxZoom } = useZoomImageRect(slideRect, zoomWrapper?.imageDimensions);

  const { zoom, offsetX, offsetY, disabled, changeZoom, changeOffsets, zoomIn, zoomOut } = useZoomState(
    imageRect,
    maxZoom,
    zoomWrapper?.zoomWrapperRef,
  );

  useZoomCallback(zoom, disabled);

  useZoomSensors(
    zoom,
    minZoom,
    maxZoom,
    disabled,
    zoomIn,
    zoomOut,
    changeZoom,
    changeOffsets,
    zoomWrapper?.zoomWrapperRef,
  );

  const zoomRef = React.useMemo(
    () => ({ zoom, minZoom, maxZoom, offsetX, offsetY, disabled, zoomIn, zoomOut, changeZoom }),
    [zoom, minZoom, maxZoom, offsetX, offsetY, disabled, zoomIn, zoomOut, changeZoom],
  );

  React.useImperativeHandle(ref, () => zoomRef, [zoomRef]);

  const context = React.useMemo(() => ({ ...zoomRef, setZoomWrapper }), [zoomRef, setZoomWrapper]);

  return <ZoomControllerContext.Provider value={context}>{children}</ZoomControllerContext.Provider>;
}

--- lightbox types ---
import * as React from "react";

import {
  ACTION_CLOSE,
  ACTION_NEXT,
  ACTION_PREV,
  ACTION_SWIPE,
  ACTIVE_SLIDE_COMPLETE,
  ACTIVE_SLIDE_ERROR,
  ACTIVE_SLIDE_LOADING,
  ACTIVE_SLIDE_PLAYING,
} from "./consts.js";

/** Lightbox external props */
export type LightboxExternalProps = DeepPartial<
  DeepPartial<DeepPartial<LightboxProps, "animation" | "toolbar" | "noScroll">, "carousel", "imageProps">,
  "controller",
  "ref"
>;

/** Lightbox properties */
export interface LightboxProps {
  // TODO v4: consider https://github.com/igordanchenko/yet-another-react-lightbox/issues/374
  /** if `true`, the lightbox is open */
  open: boolean;
  /** a callback to close the lightbox */
  close: Callback;
  /** starting slide index */
  index: number;
  /** slides to display in the lightbox */
  slides: readonly Slide[];
  /** custom render functions */
  render: Render;
  /** custom UI labels / translations */
  labels: Labels;
  /** enabled plugins */
  plugins: readonly Plugin[];
  /** toolbar settings */
  toolbar: ToolbarSettings;
  /** carousel settings */
  carousel: CarouselSettings;
  /** animation settings */
  animation: AnimationSettings;
  /** controller settings */
  controller: ControllerSettings;
  /** portal settings */
  portal: PortalSettings;
  /** NoScroll module settings */
  noScroll: NoScrollSettings;
  /** lifecycle callbacks */
  on: Callbacks;
  /** customization styles */
  styles: SlotStyles;
  /** CSS class of the lightbox root element */
  className: string;
}

/** Slide */
export type Slide = SlideTypes[SlideTypeKey];

/** Supported slide types */
export interface SlideTypes {
  /** image slide type */
  image: SlideImage;
}

/** Slide type key */
export type SlideTypeKey = keyof SlideTypes;

/** Generic slide */
export interface GenericSlide {
  type?: SlideTypeKey;
}

/** Image slide properties */
export interface SlideImage extends GenericSlide {
  /** image slide type */
  type?: "image";
  /** image URL */
  src: string;
  /** image 'alt' attribute */
  alt?: string;
  /** image width in pixels */
  width?: number;
  /** image height in pixels */
  height?: number;
  /** `object-fit` setting */
  imageFit?: ImageFit;
  /** alternative images to be passed to the 'srcSet' */
  srcSet?: readonly ImageSource[];
}

/** Image source */
export interface ImageSource {
  /** image URL */
  src: string;
  /** image width in pixels */
  width: number;
  /** image height in pixels */
  height: number;
}

/** Image fit setting */
export type ImageFit = "contain" | "cover";

/** Lightbox component */
export type Component = React.ComponentType<ComponentProps>;

/** Lightbox component properties */
export type ComponentProps = React.PropsWithChildren<Omit<LightboxProps, "slides" | "index" | "plugins">>;

/** Lightbox component tree node */
export type Node = {
  /** module */
  module: Module;
  /** module child nodes */
  children?: Node[];
};

/** Lightbox module */
export type Module = {
  /** module name */
  name: string;
  /** module component */
  component: Component;
};

/** Lightbox props augmentation */
export type Augmentation = (props: ComponentProps) => ComponentProps;

/** Container rect */
export type ContainerRect = {
  width: number;
  height: number;
};

/** Customization slots */
export type Slot = SlotType[keyof SlotType];

/** Supported customization slots */
export interface SlotType {
  /** lightbox root customization slot */
  root: "root";
  /** lightbox container customization slot */
  container: "container";
  /** lightbox slide customization slot */
  slide: "slide";
  /** lightbox button customization slot */
  button: "button";
  /** lightbox icon customization slot */
  icon: "icon";
  /** lightbox toolbar customization slot */
  toolbar: "toolbar";
  /** lightbox Prev navigation button customization slot */
  navigationPrev: "navigationPrev";
  /** lightbox Next navigation button customization slot */
  navigationNext: "navigationNext";
}

/** Customization slot CSS properties */
interface SlotCSSProperties extends React.CSSProperties {
  [key: `--yarl__${string}`]: string | number;
}

/** Customization slots styles */
export type SlotStyles = {
  [key in Slot]?: SlotCSSProperties;
};

/** Carousel settings */
export interface CarouselSettings {
  /** if `true`, the lightbox carousel doesn't wrap around */
  finite: boolean;
  /** the lightbox preloads (2 * preload + 1) slides */
  preload: number;
  /** padding around each slide (e.g., "16px", "10%" or 0) */
  padding: LengthOrPercentage;
  /** spacing between slides (e.g., "100px", "50%" or 0) */
  spacing: LengthOrPercentage;
  /** `object-fit` setting for image slides */
  imageFit: ImageFit;
  /** custom image attributes */
  imageProps: ImageProps | ((slide: Slide) => ImageProps);
}

export type LengthOrPercentage = `${number}px` | `${number}%` | number;

export type ImageProps = Omit<
  React.ImgHTMLAttributes<HTMLImageElement>,
  "src" | "alt" | "sizes" | "srcSet" | "onLoad" | "onError" | "onClick"
>;

/** Animation settings */
export interface AnimationSettings {
  /** fade-in / fade-out animation settings */
  fade: number;
  /** swipe animation settings */
  swipe: number;
  /** override for `swipe` animation settings when using keyboard navigation or navigation buttons */
  navigation?: number;
  /** animation timing function settings */
  easing: {
    /** fade-in / fade-out animation timing function */
    fade: string;
    /** slide swipe animation timing function */
    swipe: string;
    /** slide navigation animation timing function (when using keyboard navigation or navigation buttons) */
    navigation: string;
  };
}

/** Controller settings */
export interface ControllerSettings {
  /** controller ref */
  ref: React.ForwardedRef<ControllerRef>;
  // TODO v4: remove
  /** @deprecated for internal use only */
  focus: boolean;
  // TODO v4: remove
  /** @deprecated for internal use only */

--- zoom tests ---
import { act, render, screen } from "@testing-library/react";

import { lightbox, expectLightboxToBeOpen } from "../test-utils.js";
import { Zoom } from "../../../src/plugins/index.js";

describe("Zoom", () => {
  it("renders without crashing", async () => {
    render(
      lightbox({
        slides: Array.from({ length: 3 }).map((_, i) => ({
          src: `image${i + 1}`,
          width: 3000,
          height: 2000,
        })),
        plugins: [Zoom],
      }),
    );

    act(() => {
      screen.getByLabelText("Zoom in").click();
    });

    act(() => {
      screen.getByLabelText("Zoom out").click();
    });

    expectLightboxToBeOpen();
  });
});

